package br.edu.atitus.mathias_karling_stadtlober.zoo_digital.animais; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.comportamentos.*; import br.edu.atitus.mathias_karling_stadtlober.zoo_digital.especies.Reptil; public class Crocodilo extends Reptil implements Nado, Predacao { public Crocodilo(String nome, int idade) { super(nome, idade); } public void emitirSom() { System.out.println(getNome() + " emite um ronco grave."); } public void comer() { System.out.println(getNome() + " está comendo carne."); } public void nadar() { System.out.println(getNome() + " está nadando perto da margem."); } public void cacar() { System.out.println(getNome() + " está caçando por emboscada."); } }
